const incoming = $input.first().json ?? {};
const body = incoming.body ?? incoming ?? {};

const getString = (value) => typeof value === 'string' && value.trim() ? value.trim() : '';
const getArray = (value) => Array.isArray(value) ? value : [];

const action = getString(body.action) === 'launch' ? 'launch' : 'prepare';
const callback = body.callback ?? {};
const job = body.job ?? {};
const target = body.target ?? {};
const publishPackage = body.publishPackage ?? {};

return [{
  json: {
    source: getString(body.source) || 'showroom-shorts',
    action,
    dispatchedAt: getString(body.dispatchedAt) || new Date().toISOString(),
    callbackUrl: getString(callback.url),
    callbackSecretHeaderName: getString(callback.secretHeaderName) || 'x-showroom-shorts-publish-secret',
    callbackSecret: 'REPLACE_WITH_SHOWROOM_SHORTS_PUBLISH_CALLBACK_SECRET',
    jobId: getString(job.id),
    finalVideoUrl: getString(job.finalVideoUrl),
    sourceVideoUrl: getString(job.sourceVideoUrl),
    durationSeconds: Number(job.durationSeconds ?? 10),
    targetId: getString(target.id),
    channel: getString(target.channel),
    title: getString(target.title),
    description: getString(target.description),
    hashtags: getArray(target.hashtags).map((item) => String(item).trim()).filter(Boolean),
    firstComment: getString(target.firstComment),
    publishStatus: getString(target.publishStatus),
    publishPackage,
  }
}];

const title = $json.title || $json.publishPackage?.title || '';
const baseDescription = $json.channel === 'youtube'
  ? ($json.publishPackage?.descriptionWithHashtags || $json.description)
  : ($json.publishPackage?.caption || $json.description);
const firstComment = $json.publishPackage?.firstComment || $json.firstComment || '';
const hashtags = Array.isArray($json.hashtags) ? $json.hashtags.join(' ') : '';

return [{
  json: {
    ...$json,
    preparedTitle: title,
    preparedDescription: baseDescription,
    preparedFirstComment: firstComment,
    checklist: [
      `${$json.channel} 제목 점검`,
      `${$json.channel} 설명 점검`,
      '최종 MP4 URL 확인',
      '론칭 전 승인 대기'
    ],
    previewUrl: $json.finalVideoUrl,
    callbackBody: {
      targetId: $json.targetId,
      action: 'prepare',
      status: 'launch_ready',
      message: 'upload ready',
      completedAt: new Date().toISOString(),
      payload: {
        title,
        descriptionWithHashtags: baseDescription,
        firstComment,
        hashtagsText: hashtags,
        previewUrl: $json.finalVideoUrl,
        checklist: [
          `${$json.channel} 제목 점검`,
          `${$json.channel} 설명 점검`,
          '최종 MP4 URL 확인',
          '론칭 전 승인 대기'
        ]
      }
    }
  }
}];

const normalizeNode = $('입력 정규화').item.json;
const youtubeOutput = $json;
const channel = String(normalizeNode.channel || '').toLowerCase();
const finalVideoUrl = normalizeNode.finalVideoUrl || '';
const externalPostId = youtubeOutput.id || `youtube-${Date.now()}`;
const externalPostUrl = youtubeOutput.id ? `https://www.youtube.com/shorts/${youtubeOutput.id}` : `https://www.youtube.com/watch?v=${externalPostId}`;
return [{
  json: {
    ...normalizeNode,
    callbackBody: {
      targetId: normalizeNode.targetId,
      action: 'launch',
      status: 'published',
      message: 'published',
      completedAt: new Date().toISOString(),
      externalPostId,
      externalPostUrl,
      payload: { channel, finalVideoUrl, youtubeResponse: youtubeOutput }
    }
  }
}];

const normalizeNode = $('입력 정규화').item.json;
const res = $json;
const id = res.id || res.post_id || `fb-${Date.now()}`;
const finalVideoUrl = normalizeNode.finalVideoUrl || '';
const externalPostUrl = `https://www.facebook.com/watch/?v=${id}`;
return [{
  json: {
    ...normalizeNode,
    callbackBody: {
      targetId: normalizeNode.targetId,
      action: 'launch',
      status: 'published',
      message: 'published',
      completedAt: new Date().toISOString(),
      externalPostId: String(id),
      externalPostUrl,
      payload: { channel: 'facebook', finalVideoUrl, graphResponse: res }
    }
  }
}];

const normalizeNode = $('입력 정규화').item.json;
const res = $json;
const id = res.id || `ig-${Date.now()}`;
const finalVideoUrl = normalizeNode.finalVideoUrl || '';
const externalPostUrl = `https://www.instagram.com/p/${id}/`;
return [{
  json: {
    ...normalizeNode,
    callbackBody: {
      targetId: normalizeNode.targetId,
      action: 'launch',
      status: 'published',
      message: 'published',
      completedAt: new Date().toISOString(),
      externalPostId: String(id),
      externalPostUrl,
      payload: { channel: 'instagram', finalVideoUrl, graphResponse: res }
    }
  }
}];
